#include <iostream>
#include <iomanip>

class Temperature {
public:
    Temperature(double c) : m_celsius{c} {}
    double getCelsius() const { return m_celsius; }
    double getFahrenheit() const { return m_celsius * 9.0 / 5.0 + 32.0; }
private:
    double m_celsius{0.0};
};

int main() {
    double c;
    std::cin >> c;
    Temperature t{c};
    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Celsius: " << t.getCelsius() << '\n';
    std::cout << "Fahrenheit: " << t.getFahrenheit() << '\n';
    return 0;
}

